  ('diplomatic-5118c8cd-moex-00320', 'diplomatic-5118c8cd', 'diplomatic-5118c8cd-moex-110-e6f33b51', 'sub-diplomatic-5118c8cd-04', NULL, 'single_choice', '歐元（eurodollars）已經成為美國重要的外幣存款（deposits），主要是因為美國的銀行以相對於本 國貨幣存款比較狹窄的利差（narrowermargins）發行歐元存款帳戶進行歐元買賣。銀行如此操作 的原由是因為歐元存款在美國屬於什麼性質？', '["重要的兌換貨幣", "好的投資標的", "免除監控", "社會地位象徵"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:08+00:00", "source_pdf_sha1": "ab8dabb335f2", "answer_pdf_sha1": "f7c4ac93c413", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際經濟", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-泰文組"}'::jsonb, NULL),
