  ('diplomatic-5118c8cd-moex-00322', 'diplomatic-5118c8cd', 'diplomatic-5118c8cd-moex-110-e6f33b51', 'sub-diplomatic-5118c8cd-04', NULL, 'single_choice', '有關貨幣政策於固定匯率機制下的敘述，下列何者正確？', '["具有國際準備貨幣地位者，該國將喪失貨幣政策自主性", "將本國貨幣幣值釘住他國貨幣者，將擁有更高之貨幣政策自主性", "將本國貨幣幣值釘住他國貨幣者，將擁有控制他國貨幣政策的能力", "將本國貨幣幣值釘住他國貨幣者，將不具有自己國家之貨幣政策自主性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:08+00:00", "source_pdf_sha1": "ab8dabb335f2", "answer_pdf_sha1": "f7c4ac93c413", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際經濟", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-泰文組"}'::jsonb, NULL),
  ('diplomatic-5118c8cd-moex-00323', 'diplomatic-5118c8cd', 'diplomatic-5118c8cd-moex-110-c655adf3', 'sub-diplomatic-5118c8cd-05', NULL, 'single_choice', '有關民主原則，下列敘述何者錯誤？', '["我國憲政體制係採直接民主制", "我國之主權屬於全體國民", "人民行使國家主權的方式，多係透過投票的方式為之", "原則上以多數決定之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:08+00:00", "source_pdf_sha1": "4869a4c6fee1", "answer_pdf_sha1": "9956c1dccdce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-泰文組"}'::jsonb, NULL),
  ('diplomatic-5118c8cd-moex-00324', 'diplomatic-5118c8cd', 'diplomatic-5118c8cd-moex-110-c655adf3', 'sub-diplomatic-5118c8cd-05', NULL, 'single_choice', '憲法及增修條文關於「軍人」之規定，下列敘述何者錯誤？', '["現役軍人不得兼任文官", "現役軍人應受軍事審判", "國家應對軍人退役後之就學、就業予以保障", "全國陸海空軍應超出黨派"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:08+00:00", "source_pdf_sha1": "4869a4c6fee1", "answer_pdf_sha1": "9956c1dccdce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-泰文組"}'::jsonb, NULL),
  ('diplomatic-5118c8cd-moex-00325', 'diplomatic-5118c8cd', 'diplomatic-5118c8cd-moex-110-c655adf3', 'sub-diplomatic-5118c8cd-05', NULL, 'single_choice', '依司法院釋字第756號解釋意旨，關於憲法秘密通訊自由，下列敘述何者錯誤？', '["受刑人在監禁期間，人身自由遭受限制，惟其秘密通訊自由等基本權利，仍受憲法之保障", "監獄長官閱讀受刑人發受書信，涉及對秘密通訊自由核心內涵之干預", "監獄長官為確認有無夾帶違禁品而檢查受刑人書信，並不當然影響通訊內容之秘密性", "監獄長官令受刑人刪除書信部分內容後再發出，如以法律或法律具體明確授權之命令定之，即為憲法所許"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:08+00:00", "source_pdf_sha1": "4869a4c6fee1", "answer_pdf_sha1": "9956c1dccdce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-泰文組"}'::jsonb, NULL),
  ('diplomatic-5118c8cd-moex-00326', 'diplomatic-5118c8cd', 'diplomatic-5118c8cd-moex-110-c655adf3', 'sub-diplomatic-5118c8cd-05', NULL, 'single_choice', '依司法院大法官解釋，若法律規定國家對宗教之監督僅適用於佛、道教，未對其他宗教為相同之限制，該 法律規定是否合憲？', '["違憲，因為宗教自由乃是不得以法律限制之基本權", "違憲，因為宗教自由之限制乃是內政部之行政保留事項", "違憲，因為違反宗教中立原則與宗教平等原則", "合憲，因為國家對宗教自由得以法律為必要之限制"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:08+00:00", "source_pdf_sha1": "4869a4c6fee1", "answer_pdf_sha1": "9956c1dccdce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-泰文組"}'::jsonb, NULL),
